import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard(){

  const [jobs,setJobs]=useState([]);

  useEffect(()=>{
    axios.get("http://localhost:5000/api/jobs/all")
    .then(res=>setJobs(res.data));
  },[]);

  return(
    <div>
      <Navbar/>

      <h2>Job Requests</h2>

      {jobs.map(j=>(
        <div key={j._id} style={{border:"1px solid #ddd",padding:10,margin:10}}>

          <h3>{j.workerName}</h3>
          <p>{j.workType}</p>
          <p>Status: {j.status}</p>
          <p>Slots: {j.timeSlots?.join(", ")}</p>

          <button onClick={()=>axios.put(`http://localhost:5000/api/jobs/accept/${j._id}`)}>
            Accept
          </button>

          <button onClick={()=>axios.put(`http://localhost:5000/api/jobs/reject/${j._id}`)}>
            Reject
          </button>

        </div>
      ))}
    </div>
  )
}
